// Quiz content for Cours35 — Jazz avancé : Reharmonisation et improvisation

export interface Question { q: string; opts: string[]; a: number; fb: string; }
export interface Cours35Locale { questions: Question[]; }

const questionsFr: Question[] = [
  { q: "Qu'est-ce que la 'substitution diatonique' en reharmonisation ?", opts: ["Remplacer un accord par un accord d'une autre tonalité", "Remplacer un accord par un autre accord ayant la même fonction harmonique dans la même tonalité — ex. I ↔ III ↔ VI", "Remplacer tous les accords par des accords de dominante", "Changer de tonalité à chaque accord"], a: 1, fb: "La substitution diatonique exploite les accords partageant des notes communes dans la même tonalité. I ↔ III ↔ VI fonctionnent car ils partagent 2 notes sur 3. II ↔ IV sont interchangeables car ils partagent la même fonction sous-dominante et 2 notes communes. La mélodie reste harmonisable avec le substitut." },
  { q: "Quel est le principe fondamental de la substitution tritonique ?", opts: ["Remplacer la tonique par la dominante", "Remplacer un accord de dominante V7 par l'accord de dominante situé un triton plus bas — ils partagent les mêmes guide-tones (3e et 7e, échangées)", "Remplacer le IIm7 par le IVmaj7", "Transposer toute la grille un triton plus haut"], a: 1, fb: "G7 (Sol–Si–Ré–Fa) et Db7 (Réb–Fa–Lab–Do) partagent les mêmes guide-tones : Si (3e de G7) = Do# (7e de Db7) et Fa (7e de G7) = Mib (3e de Db7). Ces deux notes échangent leurs rôles — c'est pourquoi les deux accords ont le même pouvoir résolutif vers C. La basse descend par demi-ton (Sol→Réb) au lieu d'une quinte (Sol→Do)." },
  { q: "Qu'est-ce que le 'modal interchange avancé' au-delà de l'éolien et du mixolydien ?", opts: ["Utiliser uniquement les modes ionien et dorien", "Emprunter des accords de modes parallèles non diatoniques — incluant le phrygien (bII) et le locrien (bII dim)", "Changer de tonalité pour un seul accord", "Jouer en mode majeur et mineur simultanément"], a: 1, fb: "Au-delà des emprunts standards (bVI de l'éolien, bVII du mixolydien), le modal interchange avancé permet d'emprunter au mode phrygien (bII Majeur — l'accord napolitain) ou au mode locrien (VIIdim). En Do majeur : Réb Majeur (phrygien), Si dim (locrien). Ces emprunts plus rares créent des couleurs très caractéristiques." },
  { q: "Qu'est-ce que le 'chromatic mediant' (médiante chromatique) en reharmonisation ?", opts: ["Remplacer la tonique par la médiante de la gamme chromatique", "Remplacement de l'accord de tonique par un accord dont la fondamentale est à une tierce (majeure ou mineure) — majeure → mineure ou inversement", "Utiliser exclusivement des accords chromatiques altérés", "Jouer la mélodie un demi-ton plus haut"], a: 1, fb: "Le chromatic mediant remplace I par III, VI ou leur équivalent modifié. En Do majeur : I (CMaj) peut être remplacé par EMaj (tierce majeure, mode parallèle différent) ou AbMaj (tierce majeure descendante). Ces substitutions créent une couleur 'magique' et cinématographique très utilisée par John Williams et Hans Zimmer." },
  { q: "Qu'est-ce qu'un 'chord scale' (gamme par accord) ?", opts: ["Une gamme construite sur les notes de l'accord", "La gamme spécifique à jouer sur chaque accord dans un contexte harmonique donné — chaque accord détermine quelle gamme est idéale pour l'improvisation", "Un accord construit sur les notes de la gamme", "Une gamme chromatique altérée"], a: 1, fb: "Le chord scale associe à chaque accord la gamme la plus compatible. CMaj7 → lydien (si on veut #11) ou ionien (pour la couleur classique). Dm7 → dorien (pour la 13e naturelle et la couleur jazz). G7 → mixolydien (standard) ou altéré (super-locrien, pour tension maximale). Le chord scale détermine quelles notes sont 'disponibles' pour l'improvisation." },
  { q: "Sur quelle gamme improviser sur G7alt (accord dominant altéré) ?", opts: ["Gamme majeure de Sol", "Gamme mixolydienne de Sol", "Gamme altérée de Sol (super-locrien = 7e mode de la mineure mélodique)", "Gamme pentatonique de Sol"], a: 2, fb: "G7alt utilise la gamme altérée de Sol (Sol–Lab–Sib–Si–Réb–Mib–Fa), aussi appelée super-locrien car c'est le 7e mode de la gamme mineure mélodique de Lab. Elle contient toutes les tensions altérées : b9 (Lab), #9 (La# = Sib), #11 (Do# = Réb), b13 (Mib). C'est la gamme de la tension maximale sur V7." },
  { q: "Qu'est-ce que le 'turnaround' (tourne) en jazz ?", opts: ["Un aller-retour entre tonique et dominante", "Une courte progression (souvent 2-4 accords) à la fin d'une section qui ramène vers le début — typiquement I–VI–II–V ou III–VI–II–V", "Un solo instrumental", "Un changement de tempo"], a: 1, fb: "Le turnaround est la progression de fin de section qui relance la grille vers son début. La formule classique : I–VI–II–V (CMaj–Am7–Dm7–G7). Le VI est souvent remplacé par un substitut (chromatic mediant, substitut tritonique). Coltrane a réinventé le turnaround avec ses substitutions de tierces majeures." },
  { q: "Dans 'Autumn Leaves', quelle est la progression harmonique de base des 8 premières mesures ?", opts: ["I–IV–VII–III–VI–II–V–I (cycle de quintes complet)", "Cm7–F7–BbMaj7–EbMaj7–Am7b5–D7–Gm (cycle de quintes en Sol mineur)", "Im–bVI–bIII–bVII–Im", "IIm7–V7–IMaj7 répété 4 fois"], a: 1, fb: "Autumn Leaves (Les Feuilles mortes) suit la progression classique : cycle de quintes en Sol mineur — Cm7–F7–BbMaj7–EbMaj7–Am7b5–D7–Gm. C'est le standard de jazz le plus pédagogique car il contient à la fois un II–V–I en Sib majeur et un II–V–I en Sol mineur, avec pivot harmonique entre les deux." },
  { q: "Qu'est-ce que la 'reharmonisation à la Coltrane' appliquée à un standard ?", opts: ["Remplacer chaque accord par son substitut tritonique", "Remplacer un II–V–I par plusieurs II–V–I successifs à distance de tierce majeure (cycle de trois toniques)", "Jouer uniquement des accords de 7e diminués", "Supprimer tous les accords mineurs"], a: 1, fb: "La reharmonisation à la Coltrane divise le cycle tonal en tierces majeures. Au lieu d'un seul II–V–I (Dm7–G7–CMaj), on traverse trois II–V–I à distance de tierce : Dm7–G7–CMaj → Bm7–E7–AMaj → Abm7–Db7–GbMaj → retour. Le triangle Si–Sol–Mib–Si couvre les 12 tonalités en 3 sauts de tierce." },
  { q: "Quelle est la différence entre 'reharmonisation' et 'harmonisation' ?", opts: ["Ce sont des synonymes", "L'harmonisation ajoute des accords sous une mélodie sans accompagnement ; la reharmonisation remplace des accords existants par d'autres sous la même mélodie", "La reharmonisation concerne uniquement le jazz, l'harmonisation la musique classique", "La reharmonisation est plus simple"], a: 1, fb: "Harmoniser = créer une première harmonisation pour une mélodie nue. Réharmoniser = remplacer les accords d'une harmonisation existante par d'autres, tout en conservant la mélodie. La contrainte principale : la note mélodique doit être compatible avec le nouvel accord (fondamentale, tierce, quinte, 7e, ou extension disponible)." },
  { q: "Comment déterminer si une note mélodique est compatible avec un accord de reharmonisation ?", opts: ["La note mélodique doit être dans la gamme de Do majeur", "La note mélodique doit être une fondamentale, tierce, quinte, 7e ou extension disponible de l'accord — pas une note évitée", "Toutes les notes sont compatibles avec tous les accords", "La note mélodique doit être plus aiguë que la basse"], a: 1, fb: "La contrainte principale de la reharmonisation : la mélodie ne doit pas frotter contre l'accord. Si la note mélodique est une 'note évitée' (ex : 11 naturel sur IMaj7 — Fa sur CMaj7 crée un frottement de demi-ton avec la tierce Mi), l'accord est mal choisi. Préférer un accord dont la note mélodique est fondamentale, 3e, 5te, 7e ou tension disponible." },
  { q: "Qu'est-ce qu'un 'back-cycling' en reharmonisation jazz ?", opts: ["Jouer la grille à l'envers", "Ajouter des accords de dominante qui précèdent chaque accord important par mouvement de quintes — IIm→V avant tout accord cible", "Répéter la grille deux fois plus lentement", "Retirer des accords de la grille originale"], a: 1, fb: "Le back-cycling ajoute des dominantes secondaires avant chaque accord cible. Si la grille a CMaj7, on précède par G7 (dominant de C). Si elle a Am7, on précède par E7 (dominant de A). Cette technique 'remonte le cycle des quintes' et densifie le rythme harmonique — typique du jazz bebop." },
  { q: "Qu'est-ce que le 'diminished substitution' (substitution diminuée) en jazz ?", opts: ["Remplacer un accord par son diminué parallèle", "Remplacer un accord de dominante 7b9 par l'accord diminué construit sur sa note guide — ils partagent 4 notes communes", "Jouer des accords diminués sur tous les temps faibles", "Utiliser uniquement des gammes diminuées"], a: 1, fb: "G7b9 (Sol–Si–Ré–Fa–Lab) partage 4 notes avec le B°7 (Si–Ré–Fa–Lab). Ces deux accords sont harmoniquement équivalents — l'un peut remplacer l'autre. L'accord diminué peut 'remonter' la tonique de demi-ton : B°7 = Bdim = D°7 = F°7 = Ab°7 (les 4 formes du même accord), toutes substituables à G7b9." },
  { q: "Quelle est la progression II–V–I en La bémol majeur ?", opts: ["Am7–D7–GMaj7", "Bbm7–Eb7–AbMaj7", "Gm7–C7–FMaj7", "Fm7–Bb7–EbMaj7"], a: 1, fb: "En Lab majeur : IIm7 = Sib mineur 7 (Bbm7), V7 = Mi bémol 7 (Eb7), IMaj7 = La bémol majeur 7 (AbMaj7). Le II–V–I en Lab majeur est Bbm7–Eb7–AbMaj7. La fondamentale de II est un ton au-dessus de I (Sib au-dessus de Lab), la fondamentale de V est une quarte au-dessus de I (Mib au-dessus de Lab)." },
  { q: "Qu'est-ce qu'un 'passing chord' (accord de passage) en reharmonisation ?", opts: ["Un accord joué très doucement", "Un accord chromatique interstitiel inséré entre deux accords pour créer un mouvement de basse chromatique fluide", "Un accord de transition obligatoire", "L'accord de sous-dominante dans toute progression"], a: 1, fb: "Un passing chord est un accord ajouté (souvent diminué ou dominant) entre deux accords de la grille pour créer un mouvement chromatique de basse. CMaj7→Am7 peut devenir CMaj7→C#°7→Am7. La basse fait Do–Do#–La, le passing chord crée une tension chromatique que l'accord suivant résout." },
  { q: "Qu'est-ce qu'un 'shell voicing' en jazz ?", opts: ["Un accord joué avec la coquille d'une main seulement", "Un accord réduit à ses notes essentielles : fondamentale + 3e + 7e (sans quinte) — squelette de l'accord", "Un accord en position ouverte", "Un accord sans fondamentale"], a: 1, fb: "Le shell voicing (voicing coquille) garde seulement fondamentale, 3e et 7e — les guide-tones essentiels. La quinte est omise car elle n'ajoute pas de couleur. CMaj7 shell : Do–Mi–Si. G7 shell : Sol–Si–Fa. Ce voicing sonne épuré et laisse de l'espace pour la mélodie et les extensions. Idéal pour l'accompagnement de voix." },
  { q: "Comment construire un 'drop 2 voicing' à partir d'un accord fermé (close position) ?", opts: ["Descendre la fondamentale d'une octave", "Prendre un accord en position fermée et descendre la 2e voix (depuis le haut) d'une octave vers le bas", "Jouer l'accord deux fois plus grave", "Omettre la note la plus aiguë"], a: 1, fb: "Drop 2 : CMaj7 fermé (Do–Mi–Sol–Si, du grave à l'aigu). La 2e voix depuis le haut est Sol. La descendre d'une octave : Do–Sol(8vb)–Si–Mi. Résultat : Do–Sol–Si–Mi — voicing ouvert et pianistique. Cette technique est fondamentale pour les guitaristes jazz et les pianistes — elle ouvre l'accord vers un registre plus large." },
  { q: "Qu'est-ce que le 'rootless voicing' (voicing sans fondamentale) en jazz ?", opts: ["Un accord joué sans le musicien principal", "Un voicing qui omet la fondamentale — la 3e, la 7e et les extensions créent la couleur sans l'ancrage tonal de la fondamentale", "Un accord joué sans mesure", "Un accord joué uniquement en octaves"], a: 1, fb: "Le rootless voicing élimine la fondamentale car elle est jouée par la contrebasse. Sans fondamentale, l'accord sonne plus 'ouvert', moins ancré — idéal pour les harmonies flottantes du jazz modal. CMaj9 rootless : Mi–Sol–Si–Ré (3e–5te–7e–9e). G13 rootless : Si–Ré–Fa–Mi (3e–5te–7e–13e)." },
  { q: "Comment construire le 'So What voicing' sur n'importe quelle note de basse ?", opts: ["Note + tierce + tierce + tierce + quinte", "Note + quarte + quarte + quarte + tierce majeure au sommet (4 quartes empilées + tierce maj)", "Note + quinte + tierce + quinte", "Note + seconde + tierce + quarte"], a: 1, fb: "Le So What voicing suit toujours la formule : Note + quarte + quarte + quarte + tierce majeure. Sur Ré : Ré–Sol–Do–Fa–La. Sur Sol : Sol–Do–Fa–Sib–Ré. Sur Do : Do–Fa–Sib–Mib–Sol. Cette formule est universelle — elle transpose exactement sur les 12 notes chromatiques. C'est le voicing signature du jazz modal." },
  { q: "Pourquoi les 'quartal voicings' sont-ils particulièrement adaptés au jazz modal ?", opts: ["Parce qu'ils sont plus faciles à jouer", "Parce que leur ambiguïté modale (ni majeur ni mineur) convient parfaitement aux modalités ouvertes sans progression fonctionnelle forte — ils 'planent' harmoniquement", "Parce qu'ils sont plus graves", "Parce qu'ils n'ont pas de septième"], a: 1, fb: "Le jazz modal (Miles Davis, John Coltrane, McCoy Tyner) utilise peu de progressions fonctionnelles V→I — l'harmonie reste statique ou change lentement. Les voicings quartaux sont parfaits pour ce contexte car leur absence de tierce évite de définir un mode majeur ou mineur précis — l'accord est ambiguë et 'flotte' harmoniquement." },
];

const questionsEn: Question[] = [
  { q: "What is 'diatonic substitution' in reharmonization?", opts: ["Replacing a chord with one from another key", "Replacing a chord with another chord of the same harmonic function in the same key — e.g. I ↔ III ↔ VI", "Replacing all chords with dominant chords", "Changing key on every chord"], a: 1, fb: "Diatonic substitution exploits chords sharing common tones in the same key. I ↔ III ↔ VI work because they share 2 out of 3 notes. II ↔ IV are interchangeable because they share the same subdominant function and 2 common tones. The melody remains harmonizable with the substitute." },
  { q: "What is the fundamental principle of tritone substitution?", opts: ["Replacing the tonic with the dominant", "Replacing a V7 dominant chord with the dominant chord a tritone below — they share the same guide-tones (3rd and 7th, swapped)", "Replacing IIm7 with IVmaj7", "Transposing the entire chart a tritone up"], a: 1, fb: "G7 (G–B–D–F) and Db7 (Db–F–Ab–C) share the same guide-tones: B (3rd of G7) = C# (7th of Db7) and F (7th of G7) = Eb (3rd of Db7). These two notes swap roles — that is why both chords have the same resolving power toward C. The bass descends by half step (G→Db) instead of a fifth (G→C)." },
  { q: "What is 'advanced modal interchange' beyond Aeolian and Mixolydian?", opts: ["Using only Ionian and Dorian modes", "Borrowing chords from non-diatonic parallel modes — including Phrygian (bII) and Locrian (bII dim)", "Changing key for a single chord", "Playing major and minor mode simultaneously"], a: 1, fb: "Beyond standard borrowings (bVI from Aeolian, bVII from Mixolydian), advanced modal interchange allows borrowing from Phrygian (bII Major — the Neapolitan chord) or Locrian (VIIdim). In C major: Db Major (Phrygian), B dim (Locrian). These rarer borrowings create very distinctive colors." },
  { q: "What is the 'chromatic mediant' in reharmonization?", opts: ["Replacing the tonic with the mediant of the chromatic scale", "Replacing the tonic chord with a chord whose root is a third (major or minor) away — major → minor or vice versa", "Using exclusively altered chromatic chords", "Playing the melody a half step higher"], a: 1, fb: "The chromatic mediant replaces I with III, VI or their modified equivalent. In C major: I (CMaj) can be replaced by EMaj (major third, different parallel mode) or AbMaj (descending major third). These substitutions create a 'magical', cinematic color widely used by John Williams and Hans Zimmer." },
  { q: "What is a 'chord scale'?", opts: ["A scale built on the notes of the chord", "The specific scale to play over each chord in a given harmonic context — each chord determines which scale is ideal for improvisation", "A chord built on the notes of the scale", "An altered chromatic scale"], a: 1, fb: "A chord scale pairs each chord with its most compatible scale. CMaj7 → Lydian (for #11) or Ionian (for classic color). Dm7 → Dorian (for natural 13th and jazz color). G7 → Mixolydian (standard) or Altered (super-Locrian, for maximum tension). The chord scale determines which notes are 'available' for improvisation." },
  { q: "Which scale should you improvise over G7alt (altered dominant)?", opts: ["G major scale", "G Mixolydian scale", "G altered scale (super-Locrian = 7th mode of melodic minor)", "G pentatonic scale"], a: 2, fb: "G7alt uses the G altered scale (G–Ab–Bb–B–Db–Eb–F), also called super-Locrian because it is the 7th mode of the Ab melodic minor scale. It contains all altered tensions: b9 (Ab), #9 (A# = Bb), #11 (C# = Db), b13 (Eb). It is the maximum tension scale over V7." },
  { q: "What is a 'turnaround' in jazz?", opts: ["A back-and-forth between tonic and dominant", "A short progression (often 2–4 chords) at the end of a section that leads back to the beginning — typically I–VI–II–V or III–VI–II–V", "An instrumental solo", "A tempo change"], a: 1, fb: "The turnaround is the end-of-section progression that relaunches the chart toward its beginning. Classic formula: I–VI–II–V (CMaj–Am7–Dm7–G7). The VI is often replaced by a substitute (chromatic mediant, tritone substitute). Coltrane reinvented the turnaround with his major-third substitutions." },
  { q: "In 'Autumn Leaves', what is the basic harmonic progression of the first 8 bars?", opts: ["I–IV–VII–III–VI–II–V–I (complete circle of fifths)", "Cm7–F7–BbMaj7–EbMaj7–Am7b5–D7–Gm (circle of fifths in G minor)", "Im–bVI–bIII–bVII–Im", "IIm7–V7–IMaj7 repeated 4 times"], a: 1, fb: "Autumn Leaves follows the classic progression: circle of fifths in G minor — Cm7–F7–BbMaj7–EbMaj7–Am7b5–D7–Gm. It is the most pedagogically rich jazz standard because it contains both a II–V–I in Bb major and a II–V–I in G minor, with a harmonic pivot between the two." },
  { q: "What is 'Coltrane substitution' applied to a standard?", opts: ["Replacing each chord with its tritone substitute", "Replacing a II–V–I with successive II–V–I progressions a major third apart (cycle of three tonics)", "Playing only diminished 7th chords", "Removing all minor chords"], a: 1, fb: "Coltrane substitution divides the tonal cycle into major thirds. Instead of a single II–V–I (Dm7–G7–CMaj), you traverse three II–V–I progressions a third apart: Dm7–G7–CMaj → Bm7–E7–AMaj → Abm7–Db7–GbMaj → return. The B–G–Eb–B triangle covers all 12 keys in 3 third jumps." },
  { q: "What is the difference between 'reharmonization' and 'harmonization'?", opts: ["They are synonyms", "Harmonization adds chords under an unaccompanied melody; reharmonization replaces existing chords with others under the same melody", "Reharmonization applies only to jazz, harmonization only to classical music", "Reharmonization is simpler"], a: 1, fb: "To harmonize = create a first harmonization for a bare melody. To reharmonize = replace the chords of an existing harmonization with others, while keeping the melody. The main constraint: the melodic note must be compatible with the new chord (root, third, fifth, 7th, or available extension)." },
  { q: "How do you determine whether a melodic note is compatible with a reharmonization chord?", opts: ["The melodic note must be in the C major scale", "The melodic note must be a root, third, fifth, 7th or available extension of the chord — not an avoid note", "All notes are compatible with all chords", "The melodic note must be higher than the bass"], a: 1, fb: "The main constraint of reharmonization: the melody must not clash against the chord. If the melodic note is an 'avoid note' (e.g., natural 11 on IMaj7 — F on CMaj7 creates a half-step rub with the third E), the chord is wrong. Prefer a chord whose melodic note is a root, 3rd, 5th, 7th or available tension." },
  { q: "What is 'back-cycling' in jazz reharmonization?", opts: ["Playing the chart backwards", "Adding dominant chords that precede each important chord by fifth motion — IIm→V before every target chord", "Repeating the chart twice as slowly", "Removing chords from the original chart"], a: 1, fb: "Back-cycling adds secondary dominants before every target chord. If the chart has CMaj7, precede it with G7 (dominant of C). If it has Am7, precede with E7 (dominant of A). This technique 'climbs back up the circle of fifths' and densifies the harmonic rhythm — typical of bebop jazz." },
  { q: "What is 'diminished substitution' in jazz?", opts: ["Replacing a chord with its parallel diminished", "Replacing a dominant 7b9 chord with the diminished chord built on its guide tone — they share 4 common tones", "Playing diminished chords on all weak beats", "Using only diminished scales"], a: 1, fb: "G7b9 (G–B–D–F–Ab) shares 4 notes with B°7 (B–D–F–Ab). These two chords are harmonically equivalent — one can replace the other. The diminished chord can 'climb' the tonic by a half step: B°7 = Bdim = D°7 = F°7 = Ab°7 (the 4 inversions of the same chord), all substitutable for G7b9." },
  { q: "What is the II–V–I progression in A-flat major?", opts: ["Am7–D7–GMaj7", "Bbm7–Eb7–AbMaj7", "Gm7–C7–FMaj7", "Fm7–Bb7–EbMaj7"], a: 1, fb: "In Ab major: IIm7 = Bb minor 7 (Bbm7), V7 = Eb7, IMaj7 = AbMaj7. The II–V–I in Ab major is Bbm7–Eb7–AbMaj7. The II root is a whole step above I (Bb above Ab), the V root is a fourth above I (Eb above Ab)." },
  { q: "What is a 'passing chord' in reharmonization?", opts: ["A chord played very softly", "A chromatic interstitial chord inserted between two chords to create smooth chromatic bass motion", "A mandatory transition chord", "The subdominant chord in any progression"], a: 1, fb: "A passing chord is an added chord (often diminished or dominant) between two chart chords to create chromatic bass motion. CMaj7→Am7 can become CMaj7→C#°7→Am7. The bass moves C–C#–A; the passing chord creates a chromatic tension that the next chord resolves." },
  { q: "What is a 'shell voicing' in jazz?", opts: ["A chord played with the shell of one hand only", "A chord reduced to its essential notes: root + 3rd + 7th (no fifth) — the skeleton of the chord", "A chord in open position", "A chord without a root"], a: 1, fb: "The shell voicing keeps only root, 3rd and 7th — the essential guide-tones. The fifth is omitted because it adds no color. CMaj7 shell: C–E–B. G7 shell: G–B–F. This voicing sounds clean and leaves space for melody and extensions. Ideal for accompanying a singer." },
  { q: "How do you build a 'drop 2 voicing' from a close-position chord?", opts: ["Drop the root an octave", "Take a close-position chord and drop the 2nd voice from the top down by an octave", "Play the chord two octaves lower", "Omit the highest note"], a: 1, fb: "Drop 2: CMaj7 close position (C–E–G–B, low to high). The 2nd voice from the top is G. Drop it an octave: C–G(8vb)–B–E. Result: C–G–B–E — an open, pianistic voicing. This technique is fundamental for jazz guitarists and pianists — it opens the chord across a wider register." },
  { q: "What is a 'rootless voicing' in jazz?", opts: ["A chord played without the lead musician", "A voicing that omits the root — the 3rd, 7th and extensions create color without the tonal anchor of the root", "A chord played without a time signature", "A chord played only in octaves"], a: 1, fb: "The rootless voicing eliminates the root because it is played by the double bass. Without the root, the chord sounds more 'open', less anchored — ideal for floating harmonies in modal jazz. CMaj9 rootless: E–G–B–D (3rd–5th–7th–9th). G13 rootless: B–D–F–E (3rd–5th–7th–13th)." },
  { q: "How do you build the 'So What voicing' on any bass note?", opts: ["Note + third + third + third + fifth", "Note + fourth + fourth + fourth + major third on top (4 stacked fourths + major third)", "Note + fifth + third + fifth", "Note + second + third + fourth"], a: 1, fb: "The So What voicing always follows: Note + fourth + fourth + fourth + major third. On D: D–G–C–F–A. On G: G–C–F–Bb–D. On C: C–F–Bb–Eb–G. This formula is universal — it transposes exactly across all 12 chromatic notes. It is the signature voicing of modal jazz." },
  { q: "Why are 'quartal voicings' particularly suited to modal jazz?", opts: ["Because they are easier to play", "Because their modal ambiguity (neither major nor minor) perfectly suits open modalities with no strong functional progression — they 'float' harmonically", "Because they are lower in pitch", "Because they have no seventh"], a: 1, fb: "Modal jazz (Miles Davis, John Coltrane, McCoy Tyner) uses few functional V→I progressions — harmony stays static or changes slowly. Quartal voicings are perfect for this context because the absence of a third avoids defining a precise major or minor mode — the chord is ambiguous and 'floats' harmonically." },
];

const questionsDe: Question[] = [
  { q: "Was ist die 'diatonische Substitution' in der Reharmonisierung?", opts: ["Einen Akkord durch einen Akkord einer anderen Tonart ersetzen", "Einen Akkord durch einen anderen Akkord mit derselben harmonischen Funktion in derselben Tonart ersetzen — z. B. I ↔ III ↔ VI", "Alle Akkorde durch Dominantakkorde ersetzen", "Bei jedem Akkord die Tonart wechseln"], a: 1, fb: "Die diatonische Substitution nutzt Akkorde, die gemeinsame Töne in derselben Tonart teilen. I ↔ III ↔ VI funktionieren, weil sie 2 von 3 Noten teilen. II ↔ IV sind austauschbar, da sie dieselbe Subdominantfunktion und 2 gemeinsame Töne haben. Die Melodie bleibt mit dem Substitut harmonisierbar." },
  { q: "Was ist das Grundprinzip der Tritonussubstitution?", opts: ["Die Tonika durch die Dominante ersetzen", "Einen V7-Dominantakkord durch den Dominantakkord einen Tritonus tiefer ersetzen — sie teilen dieselben Guide-Tones (Terz und Septime, vertauscht)", "IIm7 durch IVmaj7 ersetzen", "Die gesamte Grille einen Tritonus höher transponieren"], a: 1, fb: "G7 (G–H–D–F) und Db7 (Des–F–As–C) teilen dieselben Guide-Tones: H (Terz von G7) = Cis (Septime von Db7) und F (Septime von G7) = Es (Terz von Db7). Diese zwei Noten tauschen ihre Rollen — deshalb haben beide Akkorde dieselbe Auflösungskraft nach C. Der Bass steigt per Halbton (G→Des) statt einer Quinte (G→C)." },
  { q: "Was ist 'erweiterter modaler Austausch' jenseits von Aeolisch und Mixolydisch?", opts: ["Nur die Ionisch- und Dorisch-Modi verwenden", "Akkorde aus nicht-diatonischen Parallelmodi ausleihen — einschliesslich Phrygisch (bII) und Lokrisch (bII dim)", "Nur für einen Akkord die Tonart wechseln", "Gleichzeitig Dur und Moll spielen"], a: 1, fb: "Jenseits der Standardausleihen (bVI aus Aeolisch, bVII aus Mixolydisch) erlaubt der erweiterte modale Austausch, aus Phrygisch (bII Dur — der neapolitanische Akkord) oder Lokrisch (VIIdim) auszuleihen. In C-Dur: Des-Dur (Phrygisch), H dim (Lokrisch). Diese selteneren Ausleihen erzeugen sehr charakteristische Klangfarben." },
  { q: "Was ist die 'chromatische Mediante' in der Reharmonisierung?", opts: ["Die Tonika durch die Mediante der chromatischen Tonleiter ersetzen", "Den Tonikakkord durch einen Akkord ersetzen, dessen Grundton eine Terz (grosse oder kleine) entfernt ist — Dur → Moll oder umgekehrt", "Ausschliesslich chromatisch alterierte Akkorde verwenden", "Die Melodie einen Halbton höher spielen"], a: 1, fb: "Die chromatische Mediante ersetzt I durch III, VI oder deren modifiziertes Äquivalent. In C-Dur: I (C-Dur) kann durch E-Dur (grosse Terz, anderer Parallelmodus) oder As-Dur (absteigende grosse Terz) ersetzt werden. Diese Substitutionen erzeugen eine 'magische', filmische Farbe, die von John Williams und Hans Zimmer häufig eingesetzt wird." },
  { q: "Was ist ein 'Chord Scale' (Akkordskala)?", opts: ["Eine Tonleiter, die auf den Noten des Akkords aufgebaut ist", "Die spezifische Tonleiter, die über jeden Akkord in einem harmonischen Kontext gespielt werden soll — jeder Akkord bestimmt die ideale Tonleiter für die Improvisation", "Ein Akkord, der auf den Noten der Tonleiter aufgebaut ist", "Eine chromatisch alterierte Tonleiter"], a: 1, fb: "Die Chord Scale ordnet jedem Akkord die kompatibleste Tonleiter zu. CMaj7 → Lydisch (für #11) oder Ionisch (für klassische Farbe). Dm7 → Dorisch (für natürliche 13. und Jazz-Farbe). G7 → Mixolydisch (Standard) oder Alteriert (Superlokrisch, für maximale Spannung). Die Chord Scale bestimmt, welche Noten für die Improvisation 'verfügbar' sind." },
  { q: "Welche Tonleiter sollte man über G7alt (alterte Dominante) improvisieren?", opts: ["G-Dur-Tonleiter", "G-Mixolydische Tonleiter", "G-Alterierte Tonleiter (Superlokrisch = 7. Modus der melodischen Moll-Tonleiter)", "G-Pentatonische Tonleiter"], a: 2, fb: "G7alt verwendet die alterierte G-Tonleiter (G–As–B–H–Des–Es–F), auch Superlokrisch genannt, da es der 7. Modus der melodischen As-Moll-Tonleiter ist. Sie enthält alle alterierten Spannungen: b9 (As), #9 (A# = B), #11 (Cis = Des), b13 (Es). Sie ist die Tonleiter der maximalen Spannung auf V7." },
  { q: "Was ist ein 'Turnaround' im Jazz?", opts: ["Ein Hin-und-Her zwischen Tonika und Dominante", "Eine kurze Progression (oft 2–4 Akkorde) am Ende eines Abschnitts, die zum Anfang zurückführt — typisch I–VI–II–V oder III–VI–II–V", "Ein Instrumentalsolo", "Ein Tempowechsel"], a: 1, fb: "Der Turnaround ist die Endprogression eines Abschnitts, die das Stück wieder zum Anfang zurückführt. Klassische Formel: I–VI–II–V (CMaj–Am7–Dm7–G7). Die VI wird oft durch ein Substitut ersetzt (chromatische Mediante, Tritonussubstitut). Coltrane erfand den Turnaround durch seine Terz-Substitutionen neu." },
  { q: "Was ist die grundlegende harmonische Progression der ersten 8 Takte in 'Autumn Leaves'?", opts: ["I–IV–VII–III–VI–II–V–I (vollständiger Quintenzirkel)", "Cm7–F7–BbMaj7–EbMaj7–Am7b5–D7–Gm (Quintenzirkel in g-Moll)", "Im–bVI–bIII–bVII–Im", "IIm7–V7–IMaj7 viermal wiederholt"], a: 1, fb: "Autumn Leaves folgt der klassischen Progression: Quintenzirkel in g-Moll — Cm7–F7–BbMaj7–EbMaj7–Am7b5–D7–Gm. Es ist der pädagogisch reichste Jazz-Standard, da er sowohl ein II–V–I in B-Dur als auch ein II–V–I in g-Moll enthält, mit harmonischem Drehpunkt dazwischen." },
  { q: "Was ist die 'Coltrane-Substitution' angewendet auf einen Standard?", opts: ["Jeden Akkord durch seinen Tritonussubstitut ersetzen", "Ein II–V–I durch mehrere aufeinanderfolgende II–V–I-Progressionen in grosser Terzentfernung ersetzen (Zyklus der drei Tonika)", "Nur verminderte Septakkorde spielen", "Alle Mollakkorde entfernen"], a: 1, fb: "Die Coltrane-Substitution unterteilt den Tonalzyklus in grosse Terzen. Statt eines einzigen II–V–I (Dm7–G7–CMaj) durchläuft man drei II–V–I-Progressionen in Terzabstand: Dm7–G7–CMaj → Hm7–E7–AMaj → Abm7–Db7–GbMaj → zurück. Das Dreieck H–G–Es–H deckt alle 12 Tonarten in 3 Terzsprüngen ab." },
  { q: "Was ist der Unterschied zwischen 'Reharmonisierung' und 'Harmonisierung'?", opts: ["Sie sind Synonyme", "Harmonisierung fügt Akkorde unter eine Melodie ohne Begleitung hinzu; Reharmonisierung ersetzt bestehende Akkorde durch andere unter derselben Melodie", "Reharmonisierung betrifft nur Jazz, Harmonisierung nur klassische Musik", "Reharmonisierung ist einfacher"], a: 1, fb: "Harmonisieren = eine erste Harmonisierung für eine blosse Melodie erstellen. Reharmonisieren = die Akkorde einer bestehenden Harmonisierung durch andere ersetzen und dabei die Melodie beibehalten. Hauptbedingung: Die Melodienote muss mit dem neuen Akkord kompatibel sein (Grundton, Terz, Quinte, Septime oder verfügbare Extension)." },
  { q: "Wie stellt man fest, ob eine Melodienote mit einem Reharmonisierungsakkord kompatibel ist?", opts: ["Die Melodienote muss in der C-Dur-Tonleiter sein", "Die Melodienote muss Grundton, Terz, Quinte, Septime oder verfügbare Extension des Akkords sein — keine Vermeidnote", "Alle Noten sind mit allen Akkorden kompatibel", "Die Melodienote muss höher als der Bass sein"], a: 1, fb: "Hauptbedingung der Reharmonisierung: Die Melodie darf nicht gegen den Akkord reiben. Wenn die Melodienote eine 'Vermeidnote' ist (z. B. natürliche 11. auf IMaj7 — F auf CMaj7 erzeugt Halbtonreibung mit der Terz E), ist der Akkord falsch gewählt. Bevorzuge einen Akkord, dessen Melodienote Grundton, Terz, Quinte, Septime oder verfügbare Spannung ist." },
  { q: "Was ist 'Back-Cycling' in der Jazz-Reharmonisierung?", opts: ["Die Grille rückwärts spielen", "Dominantakkorde hinzufügen, die jedem wichtigen Akkord per Quintenbewegung vorausgehen — IIm→V vor jedem Zielakkord", "Die Grille doppelt so langsam wiederholen", "Akkorde aus der Originalgrille entfernen"], a: 1, fb: "Back-Cycling fügt Sekundärdominanten vor jedem Zielakkord ein. Hat die Grille CMaj7, geht G7 voraus (Dominante von C). Hat sie Am7, geht E7 voraus (Dominante von A). Diese Technik 'klettert den Quintenzirkel hinauf' und verdichtet den Harmonierythmus — typisch für Bebop-Jazz." },
  { q: "Was ist die 'Diminished Substitution' im Jazz?", opts: ["Einen Akkord durch seinen parallelen verminderten ersetzen", "Einen Dominant-7b9-Akkord durch den verminderten Akkord auf seiner Guide-Tone ersetzen — sie teilen 4 gemeinsame Töne", "Verminderte Akkorde auf allen schwachen Zählzeiten spielen", "Ausschliesslich verminderte Tonleitern verwenden"], a: 1, fb: "G7b9 (G–H–D–F–As) teilt 4 Noten mit B°7 (H–D–F–As). Diese beiden Akkorde sind harmonisch äquivalent — einer kann den anderen ersetzen. Der verminderte Akkord kann die Tonika um einen Halbton 'hinaufsteigen': B°7 = Bdim = D°7 = F°7 = As°7 (die 4 Formen desselben Akkords), alle substituierbar für G7b9." },
  { q: "Was ist die II–V–I-Progression in As-Dur?", opts: ["Am7–D7–GMaj7", "Bbm7–Eb7–AbMaj7", "Gm7–C7–FMaj7", "Fm7–Bb7–EbMaj7"], a: 1, fb: "In As-Dur: IIm7 = B-Moll-7 (Bbm7), V7 = Es7 (Eb7), IMaj7 = As-Dur-7 (AbMaj7). Das II–V–I in As-Dur ist Bbm7–Eb7–AbMaj7. Der II-Grundton liegt einen Ganzton über I (B über As), der V-Grundton liegt eine Quarte über I (Es über As)." },
  { q: "Was ist ein 'Passing Chord' (Durchgangsakkord) in der Reharmonisierung?", opts: ["Ein sehr leise gespielter Akkord", "Ein chromatischer Zwischenakkord, der zwischen zwei Akkorde eingefügt wird, um eine flüssige chromatische Bassbewegung zu erzeugen", "Ein obligatorischer Übergangsakkord", "Der Subdominantakkord in jeder Progression"], a: 1, fb: "Ein Passing Chord ist ein hinzugefügter Akkord (oft vermindert oder dominant) zwischen zwei Akkorden der Grille, um chromatische Bassbewegung zu erzeugen. CMaj7→Am7 kann zu CMaj7→Cis°7→Am7 werden. Der Bass geht C–Cis–A; der Durchgangsakkord erzeugt eine chromatische Spannung, die der nächste Akkord auflöst." },
  { q: "Was ist ein 'Shell Voicing' im Jazz?", opts: ["Ein Akkord, der mit der Schale einer Hand gespielt wird", "Ein auf seine wesentlichen Töne reduzierter Akkord: Grundton + Terz + Septime (ohne Quinte) — das Skelett des Akkords", "Ein Akkord in offener Lage", "Ein Akkord ohne Grundton"], a: 1, fb: "Das Shell Voicing behält nur Grundton, Terz und Septime — die wesentlichen Guide-Tones. Die Quinte wird weggelassen, da sie keine Farbe hinzufügt. CMaj7 Shell: C–E–H. G7 Shell: G–H–F. Dieses Voicing klingt klar und lässt Platz für Melodie und Extensions. Ideal für die Gesangsbegleitung." },
  { q: "Wie baut man ein 'Drop-2-Voicing' aus einem Akkord in enger Lage?", opts: ["Den Grundton eine Oktave tiefer legen", "Einen Akkord in enger Lage nehmen und die 2. Stimme von oben eine Oktave nach unten legen", "Den Akkord zwei Oktaven tiefer spielen", "Die höchste Note weglassen"], a: 1, fb: "Drop 2: CMaj7 enge Lage (C–E–G–H, von tief nach hoch). Die 2. Stimme von oben ist G. Eine Oktave tiefer legen: C–G(8vb)–H–E. Ergebnis: C–G–H–E — ein offenes, pianistisches Voicing. Diese Technik ist fundamental für Jazzgitarristen und Pianisten — sie öffnet den Akkord über einen breiteren Register." },
  { q: "Was ist ein 'Rootless Voicing' im Jazz?", opts: ["Ein Akkord ohne den Hauptmusiker", "Ein Voicing, das den Grundton weglässt — Terz, Septime und Extensions erzeugen Farbe ohne den tonalen Anker des Grundtons", "Ein Akkord ohne Taktangabe", "Ein Akkord nur in Oktaven"], a: 1, fb: "Das Rootless Voicing eliminiert den Grundton, da er vom Kontrabass gespielt wird. Ohne Grundton klingt der Akkord 'offener', weniger verankert — ideal für schwebende Harmonien im modalen Jazz. CMaj9 rootless: E–G–H–D (Terz–Quinte–Septime–None). G13 rootless: H–D–F–E (Terz–Quinte–Septime–13.)." },
  { q: "Wie baut man das 'So-What-Voicing' auf einem beliebigen Basston?", opts: ["Note + Terz + Terz + Terz + Quinte", "Note + Quarte + Quarte + Quarte + grosse Terz oben (4 gestapelte Quarten + grosse Terz)", "Note + Quinte + Terz + Quinte", "Note + Sekunde + Terz + Quarte"], a: 1, fb: "Das So-What-Voicing folgt immer: Note + Quarte + Quarte + Quarte + grosse Terz. Auf D: D–G–C–F–A. Auf G: G–C–F–B–D. Auf C: C–F–B–Es–G. Diese Formel ist universell — sie transponiert exakt auf alle 12 chromatischen Töne. Es ist das Signatur-Voicing des modalen Jazz." },
  { q: "Warum sind 'Quartal Voicings' besonders für modalen Jazz geeignet?", opts: ["Weil sie einfacher zu spielen sind", "Weil ihre modale Ambiguität (weder Dur noch Moll) perfekt zu offenen Modalitäten ohne starke funktionale Progression passt — sie 'schweben' harmonisch", "Weil sie tiefer sind", "Weil sie keine Septime haben"], a: 1, fb: "Modaler Jazz (Miles Davis, John Coltrane, McCoy Tyner) verwendet wenig funktionale V→I-Progressionen — die Harmonie bleibt statisch oder ändert sich langsam. Quartale Voicings eignen sich perfekt für diesen Kontext, da das Fehlen einer Terz vermeidet, einen genauen Dur- oder Mollmodus zu definieren — der Akkord ist mehrdeutig und 'schwebt' harmonisch." },
];

const questionsEs: Question[] = [
  { q: "¿Qué es la 'sustitución diatónica' en la rearmonización?", opts: ["Reemplazar un acorde por uno de otra tonalidad", "Reemplazar un acorde por otro con la misma función armónica en la misma tonalidad — p. ej. I ↔ III ↔ VI", "Reemplazar todos los acordes por acordes de dominante", "Cambiar de tonalidad en cada acorde"], a: 1, fb: "La sustitución diatónica aprovecha los acordes que comparten notas comunes en la misma tonalidad. I ↔ III ↔ VI funcionan porque comparten 2 de 3 notas. II ↔ IV son intercambiables porque comparten la misma función de subdominante y 2 notas comunes. La melodía sigue siendo armonizable con el sustituto." },
  { q: "¿Cuál es el principio fundamental de la sustitución de tritono?", opts: ["Reemplazar la tónica por la dominante", "Reemplazar un acorde dominante V7 por el acorde dominante situado un tritono más abajo — comparten las mismas guide-tones (3.ª y 7.ª, intercambiadas)", "Reemplazar el IIm7 por el IVmaj7", "Transportar toda la pauta un tritono arriba"], a: 1, fb: "G7 (Sol–Si–Re–Fa) y Db7 (Re♭–Fa–La♭–Do) comparten las mismas guide-tones: Si (3.ª de G7) = Do# (7.ª de Db7) y Fa (7.ª de G7) = Mi♭ (3.ª de Db7). Estas dos notas intercambian sus roles — por eso ambos acordes tienen el mismo poder resolutivo hacia Do. El bajo desciende por semitono (Sol→Re♭) en lugar de una quinta (Sol→Do)." },
  { q: "¿Qué es el 'intercambio modal avanzado' más allá del eolio y el mixolidio?", opts: ["Usar solo los modos jónico y dórico", "Tomar prestados acordes de modos paralelos no diatónicos — incluyendo el frigio (bII) y el locrio (bII dim)", "Cambiar de tonalidad para un solo acorde", "Tocar en modo mayor y menor simultáneamente"], a: 1, fb: "Más allá de los préstamos estándar (bVI del eolio, bVII del mixolidio), el intercambio modal avanzado permite tomar prestado del modo frigio (bII Mayor — el acorde napolitano) o del locrio (VIIdim). En Do mayor: Re♭ Mayor (frigio), Si dim (locrio). Estos préstamos más raros crean colores muy característicos." },
  { q: "¿Qué es la 'mediante cromática' en rearmonización?", opts: ["Reemplazar la tónica por la mediante de la escala cromática", "Reemplazar el acorde de tónica por un acorde cuya fundamental está a una tercera (mayor o menor) — mayor → menor o viceversa", "Usar exclusivamente acordes cromáticos alterados", "Tocar la melodía un semitono más agudo"], a: 1, fb: "La mediante cromática reemplaza I por III, VI o su equivalente modificado. En Do mayor: I (Do M) puede reemplazarse por Mi M (tercera mayor, modo paralelo diferente) o La♭ M (tercera mayor descendente). Estas sustituciones crean un color 'mágico' y cinematográfico muy usado por John Williams y Hans Zimmer." },
  { q: "¿Qué es un 'chord scale' (escala por acorde)?", opts: ["Una escala construida sobre las notas del acorde", "La escala específica a tocar sobre cada acorde en un contexto armónico dado — cada acorde determina qué escala es ideal para la improvisación", "Un acorde construido sobre las notas de la escala", "Una escala cromática alterada"], a: 1, fb: "El chord scale asocia a cada acorde la escala más compatible. CMaj7 → lidio (para #11) o jónico (para el color clásico). Dm7 → dórico (para la 13.ª natural y el color jazz). G7 → mixolidio (estándar) o alterado (superlocrio, para tensión máxima). El chord scale determina qué notas están 'disponibles' para improvisar." },
  { q: "¿Sobre qué escala improvisar en G7alt (dominante alterado)?", opts: ["Escala mayor de Sol", "Escala mixolidia de Sol", "Escala alterada de Sol (superlocrio = 7.º modo de la menor melódica)", "Escala pentatónica de Sol"], a: 2, fb: "G7alt usa la escala alterada de Sol (Sol–La♭–Si♭–Si–Re♭–Mi♭–Fa), también llamada superlocria porque es el 7.º modo de la escala menor melódica de La♭. Contiene todas las tensiones alteradas: b9 (La♭), #9 (La# = Si♭), #11 (Do# = Re♭), b13 (Mi♭). Es la escala de tensión máxima sobre V7." },
  { q: "¿Qué es un 'turnaround' en jazz?", opts: ["Un vaivén entre tónica y dominante", "Una progresión corta (a menudo 2–4 acordes) al final de una sección que regresa al principio — típicamente I–VI–II–V o III–VI–II–V", "Un solo instrumental", "Un cambio de tempo"], a: 1, fb: "El turnaround es la progresión de final de sección que relanza la pauta hacia su inicio. Fórmula clásica: I–VI–II–V (CMaj–Am7–Dm7–G7). El VI a menudo se reemplaza por un sustituto (mediante cromática, sustituto de tritono). Coltrane reinventó el turnaround con sus sustituciones de terceras mayores." },
  { q: "En 'Autumn Leaves', ¿cuál es la progresión armónica básica de los primeros 8 compases?", opts: ["I–IV–VII–III–VI–II–V–I (círculo de quintas completo)", "Cm7–F7–BbMaj7–EbMaj7–Am7b5–D7–Gm (círculo de quintas en Sol menor)", "Im–bVI–bIII–bVII–Im", "IIm7–V7–IMaj7 repetido 4 veces"], a: 1, fb: "Autumn Leaves sigue la progresión clásica: círculo de quintas en Sol menor — Cm7–F7–BbMaj7–EbMaj7–Am7b5–D7–Gm. Es el estándar de jazz más pedagógico porque contiene tanto un II–V–I en Si♭ mayor como un II–V–I en Sol menor, con pivote armónico entre los dos." },
  { q: "¿Qué es la 'rearmonización a la Coltrane' aplicada a un estándar?", opts: ["Reemplazar cada acorde por su sustituto de tritono", "Reemplazar un II–V–I por varios II–V–I sucesivos a distancia de tercera mayor (ciclo de tres tónicas)", "Tocar solo acordes de séptima disminuida", "Eliminar todos los acordes menores"], a: 1, fb: "La rearmonización a la Coltrane divide el ciclo tonal en terceras mayores. En lugar de un solo II–V–I (Dm7–G7–CMaj), se recorren tres II–V–I a distancia de tercera: Dm7–G7–CMaj → Hm7–E7–AMaj → Abm7–Db7–GbMaj → retorno. El triángulo Si–Sol–Mi♭–Si cubre las 12 tonalidades en 3 saltos de tercera." },
  { q: "¿Cuál es la diferencia entre 'rearmonización' y 'armonización'?", opts: ["Son sinónimos", "La armonización añade acordes bajo una melodía sin acompañamiento; la rearmonización reemplaza acordes existentes por otros bajo la misma melodía", "La rearmonización solo concierne al jazz, la armonización a la música clásica", "La rearmonización es más sencilla"], a: 1, fb: "Armonizar = crear una primera armonización para una melodía desnuda. Rearmonizar = reemplazar los acordes de una armonización existente por otros, conservando la melodía. Condición principal: la nota melódica debe ser compatible con el nuevo acorde (fundamental, tercera, quinta, 7.ª o extensión disponible)." },
  { q: "¿Cómo se determina si una nota melódica es compatible con un acorde de rearmonización?", opts: ["La nota melódica debe estar en la escala de Do mayor", "La nota melódica debe ser fundamental, tercera, quinta, 7.ª o extensión disponible del acorde — no una nota evitada", "Todas las notas son compatibles con todos los acordes", "La nota melódica debe ser más aguda que el bajo"], a: 1, fb: "Condición principal de la rearmonización: la melodía no debe frotar contra el acorde. Si la nota melódica es una 'nota evitada' (ej.: 11.ª natural sobre IMaj7 — Fa sobre CMaj7 crea fricción de semitono con la tercera Mi), el acorde está mal elegido. Preferir un acorde cuya nota melódica sea fundamental, 3.ª, 5.ª, 7.ª o tensión disponible." },
  { q: "¿Qué es el 'back-cycling' en la rearmonización jazz?", opts: ["Tocar la pauta al revés", "Añadir acordes de dominante que preceden a cada acorde importante por movimiento de quintas — IIm→V antes de cada acorde objetivo", "Repetir la pauta el doble de lento", "Quitar acordes de la pauta original"], a: 1, fb: "El back-cycling añade dominantes secundarias antes de cada acorde objetivo. Si la pauta tiene CMaj7, se precede de G7 (dominante de Do). Si tiene Am7, se precede de E7 (dominante de La). Esta técnica 'sube el círculo de quintas' y densifica el ritmo armónico — típico del jazz bebop." },
  { q: "¿Qué es la 'sustitución disminuida' en jazz?", opts: ["Reemplazar un acorde por su disminuido paralelo", "Reemplazar un acorde dominante 7b9 por el acorde disminuido construido sobre su guide-tone — comparten 4 notas comunes", "Tocar acordes disminuidos en todos los tiempos débiles", "Usar solo escalas disminuidas"], a: 1, fb: "G7b9 (Sol–Si–Re–Fa–La♭) comparte 4 notas con B°7 (Si–Re–Fa–La♭). Estos dos acordes son armónicamente equivalentes — uno puede reemplazar al otro. El acorde disminuido puede 'subir' la tónica por semitono: B°7 = Bdim = D°7 = F°7 = Ab°7 (las 4 formas del mismo acorde), todas sustituibles por G7b9." },
  { q: "¿Cuál es la progresión II–V–I en La♭ mayor?", opts: ["Am7–D7–GMaj7", "Bbm7–Eb7–AbMaj7", "Gm7–C7–FMaj7", "Fm7–Bb7–EbMaj7"], a: 1, fb: "En La♭ mayor: IIm7 = Si♭ menor 7 (Bbm7), V7 = Mi♭7 (Eb7), IMaj7 = La♭ mayor 7 (AbMaj7). El II–V–I en La♭ mayor es Bbm7–Eb7–AbMaj7. La fundamental del II está un tono por encima de I (Si♭ sobre La♭), la fundamental del V está una cuarta por encima de I (Mi♭ sobre La♭)." },
  { q: "¿Qué es un 'passing chord' (acorde de paso) en rearmonización?", opts: ["Un acorde tocado muy suavemente", "Un acorde cromático intersticial insertado entre dos acordes para crear un movimiento de bajo cromático fluido", "Un acorde de transición obligatorio", "El acorde de subdominante en cualquier progresión"], a: 1, fb: "Un passing chord es un acorde añadido (a menudo disminuido o dominante) entre dos acordes de la pauta para crear movimiento cromático de bajo. CMaj7→Am7 puede convertirse en CMaj7→Do#°7→Am7. El bajo hace Do–Do#–La; el passing chord crea una tensión cromática que el siguiente acorde resuelve." },
  { q: "¿Qué es un 'shell voicing' en jazz?", opts: ["Un acorde tocado con la cáscara de una sola mano", "Un acorde reducido a sus notas esenciales: fundamental + 3.ª + 7.ª (sin quinta) — el esqueleto del acorde", "Un acorde en posición abierta", "Un acorde sin fundamental"], a: 1, fb: "El shell voicing conserva solo fundamental, 3.ª y 7.ª — los guide-tones esenciales. La quinta se omite porque no añade color. CMaj7 shell: Do–Mi–Si. G7 shell: Sol–Si–Fa. Este voicing suena limpio y deja espacio para la melodía y las extensiones. Ideal para acompañar a un cantante." },
  { q: "¿Cómo se construye un 'drop 2 voicing' a partir de un acorde en posición cerrada?", opts: ["Bajar la fundamental una octava", "Tomar un acorde en posición cerrada y bajar la 2.ª voz desde arriba una octava", "Tocar el acorde dos octavas más grave", "Omitir la nota más aguda"], a: 1, fb: "Drop 2: CMaj7 en posición cerrada (Do–Mi–Sol–Si, de grave a agudo). La 2.ª voz desde arriba es Sol. Bajarla una octava: Do–Sol(8vb)–Si–Mi. Resultado: Do–Sol–Si–Mi — voicing abierto y pianístico. Esta técnica es fundamental para guitarristas y pianistas de jazz — abre el acorde a un registro más amplio." },
  { q: "¿Qué es un 'rootless voicing' en jazz?", opts: ["Un acorde tocado sin el músico principal", "Un voicing que omite la fundamental — la 3.ª, la 7.ª y las extensiones crean el color sin el ancla tonal de la fundamental", "Un acorde tocado sin compás", "Un acorde tocado solo en octavas"], a: 1, fb: "El rootless voicing elimina la fundamental porque la toca el contrabajo. Sin fundamental, el acorde suena más 'abierto', menos anclado — ideal para las armonías flotantes del jazz modal. CMaj9 rootless: Mi–Sol–Si–Re (3.ª–5.ª–7.ª–9.ª). G13 rootless: Si–Re–Fa–Mi (3.ª–5.ª–7.ª–13.ª)." },
  { q: "¿Cómo se construye el 'So What voicing' sobre cualquier nota de bajo?", opts: ["Nota + tercera + tercera + tercera + quinta", "Nota + cuarta + cuarta + cuarta + tercera mayor encima (4 cuartas apiladas + tercera mayor)", "Nota + quinta + tercera + quinta", "Nota + segunda + tercera + cuarta"], a: 1, fb: "El So What voicing sigue siempre: Nota + cuarta + cuarta + cuarta + tercera mayor. Sobre Re: Re–Sol–Do–Fa–La. Sobre Sol: Sol–Do–Fa–Si♭–Re. Sobre Do: Do–Fa–Si♭–Mi♭–Sol. Esta fórmula es universal — se transpone exactamente a las 12 notas cromáticas. Es el voicing característico del jazz modal." },
  { q: "¿Por qué los 'quartal voicings' son particularmente adecuados para el jazz modal?", opts: ["Porque son más fáciles de tocar", "Porque su ambigüedad modal (ni mayor ni menor) se adapta perfectamente a las modalidades abiertas sin progresión funcional fuerte — 'flotan' armónicamente", "Porque son más graves", "Porque no tienen séptima"], a: 1, fb: "El jazz modal (Miles Davis, John Coltrane, McCoy Tyner) usa pocas progresiones funcionales V→I — la armonía permanece estática o cambia lentamente. Los voicings de cuartas son perfectos para este contexto porque la ausencia de tercera evita definir un modo mayor o menor preciso — el acorde es ambiguo y 'flota' armónicamente." },
];

const questionsIt: Question[] = [
  { q: "Cos'è la 'sostituzione diatonica' nella riarmonizzazione?", opts: ["Sostituire un accordo con uno di un'altra tonalità", "Sostituire un accordo con un altro accordo della stessa funzione armonica nella stessa tonalità — es. I ↔ III ↔ VI", "Sostituire tutti gli accordi con accordi di dominante", "Cambiare tonalità a ogni accordo"], a: 1, fb: "La sostituzione diatonica sfrutta gli accordi che condividono note comuni nella stessa tonalità. I ↔ III ↔ VI funzionano perché condividono 2 note su 3. II ↔ IV sono intercambiabili perché condividono la stessa funzione di sottodominante e 2 note comuni. La melodia rimane armonizzabile con il sostituto." },
  { q: "Qual è il principio fondamentale della sostituzione di tritono?", opts: ["Sostituire la tonica con la dominante", "Sostituire un accordo dominante V7 con l'accordo dominante un tritono sotto — condividono le stesse guide-tones (3a e 7a, scambiate)", "Sostituire il IIm7 con il IVmaj7", "Trasporre l'intera griglia un tritono più in alto"], a: 1, fb: "G7 (Sol–Si–Re–Fa) e Db7 (Reb–Fa–Lab–Do) condividono le stesse guide-tones: Si (3a di G7) = Do# (7a di Db7) e Fa (7a di G7) = Mib (3a di Db7). Queste due note si scambiano i ruoli — ecco perché entrambi gli accordi hanno lo stesso potere risolutivo verso Do. Il basso scende per semitono (Sol→Reb) invece di una quinta (Sol→Do)." },
  { q: "Cos'è lo 'scambio modale avanzato' oltre all'eolico e al misolidio?", opts: ["Usare solo i modi ionico e dorico", "Prendere in prestito accordi da modi paralleli non diatonici — inclusi il frigio (bII) e il locrio (bII dim)", "Cambiare tonalità per un solo accordo", "Suonare in modo maggiore e minore simultaneamente"], a: 1, fb: "Oltre ai prestiti standard (bVI dall'eolico, bVII dal misolidio), lo scambio modale avanzato permette di prendere in prestito dal modo frigio (bII Maggiore — l'accordo napoletano) o dal locrio (VIIdim). In Do maggiore: Reb Maggiore (frigio), Si dim (locrio). Questi prestiti più rari creano colori molto caratteristici." },
  { q: "Cos'è la 'mediante cromatica' nella riarmonizzazione?", opts: ["Sostituire la tonica con la mediante della scala cromatica", "Sostituire l'accordo di tonica con un accordo la cui fondamentale è a una terza (maggiore o minore) — maggiore → minore o viceversa", "Usare esclusivamente accordi cromatici alterati", "Suonare la melodia un semitono più in alto"], a: 1, fb: "La mediante cromatica sostituisce I con III, VI o il loro equivalente modificato. In Do maggiore: I (Do M) può essere sostituito da Mi M (terza maggiore, modo parallelo diverso) o Lab M (terza maggiore discendente). Queste sostituzioni creano un colore 'magico' e cinematografico molto usato da John Williams e Hans Zimmer." },
  { q: "Cos'è un 'chord scale' (scala per accordo)?", opts: ["Una scala costruita sulle note dell'accordo", "La scala specifica da suonare su ogni accordo in un contesto armonico dato — ogni accordo determina quale scala è ideale per l'improvvisazione", "Un accordo costruito sulle note della scala", "Una scala cromatica alterata"], a: 1, fb: "La chord scale associa a ogni accordo la scala più compatibile. CMaj7 → lidio (per #11) o ionico (per il colore classico). Dm7 → dorico (per la 13a naturale e il colore jazz). G7 → misolidio (standard) o alterato (superlocrio, per tensione massima). La chord scale determina quali note sono 'disponibili' per l'improvvisazione." },
  { q: "Su quale scala improvvisare su G7alt (dominante alterato)?", opts: ["Scala maggiore di Sol", "Scala misolidia di Sol", "Scala alterata di Sol (superlocrio = 7° modo del minore melodico)", "Scala pentatonica di Sol"], a: 2, fb: "G7alt usa la scala alterata di Sol (Sol–Lab–Sib–Si–Reb–Mib–Fa), detta anche superlocria perché è il 7° modo della scala minore melodica di Lab. Contiene tutte le tensioni alterate: b9 (Lab), #9 (La# = Sib), #11 (Do# = Reb), b13 (Mib). È la scala della tensione massima su V7." },
  { q: "Cos'è il 'turnaround' nel jazz?", opts: ["Un andirivieni tra tonica e dominante", "Una breve progressione (spesso 2–4 accordi) alla fine di una sezione che riconduce all'inizio — tipicamente I–VI–II–V o III–VI–II–V", "Un assolo strumentale", "Un cambio di tempo"], a: 1, fb: "Il turnaround è la progressione di fine sezione che rilancia la griglia verso il suo inizio. Formula classica: I–VI–II–V (CMaj–Am7–Dm7–G7). Il VI è spesso sostituito da un sostituto (mediante cromatica, sostituto di tritono). Coltrane ha reinventato il turnaround con le sue sostituzioni di terze maggiori." },
  { q: "In 'Autumn Leaves', qual è la progressione armonica di base dei primi 8 battute?", opts: ["I–IV–VII–III–VI–II–V–I (ciclo di quinte completo)", "Cm7–F7–BbMaj7–EbMaj7–Am7b5–D7–Gm (ciclo di quinte in Sol minore)", "Im–bVI–bIII–bVII–Im", "IIm7–V7–IMaj7 ripetuto 4 volte"], a: 1, fb: "Autumn Leaves segue la progressione classica: ciclo di quinte in Sol minore — Cm7–F7–BbMaj7–EbMaj7–Am7b5–D7–Gm. È lo standard jazz più pedagogico perché contiene sia un II–V–I in Sib maggiore sia un II–V–I in Sol minore, con un perno armonico tra i due." },
  { q: "Cos'è la 'riarmonizzazione alla Coltrane' applicata a uno standard?", opts: ["Sostituire ogni accordo con il suo sostituto di tritono", "Sostituire un II–V–I con più II–V–I successivi a distanza di terza maggiore (ciclo delle tre toniche)", "Suonare solo accordi di settima diminuita", "Rimuovere tutti gli accordi minori"], a: 1, fb: "La riarmonizzazione alla Coltrane divide il ciclo tonale in terze maggiori. Invece di un solo II–V–I (Dm7–G7–CMaj), si percorrono tre II–V–I a distanza di terza: Dm7–G7–CMaj → Hm7–E7–AMaj → Abm7–Db7–GbMaj → ritorno. Il triangolo Si–Sol–Mib–Si copre le 12 tonalità in 3 salti di terza." },
  { q: "Qual è la differenza tra 'riarmonizzazione' e 'armonizzazione'?", opts: ["Sono sinonimi", "L'armonizzazione aggiunge accordi sotto una melodia senza accompagnamento; la riarmonizzazione sostituisce accordi esistenti con altri sotto la stessa melodia", "La riarmonizzazione riguarda solo il jazz, l'armonizzazione la musica classica", "La riarmonizzazione è più semplice"], a: 1, fb: "Armonizzare = creare una prima armonizzazione per una melodia nuda. Riarmonizzare = sostituire gli accordi di un'armonizzazione esistente con altri, mantenendo la melodia. Vincolo principale: la nota melodica deve essere compatibile con il nuovo accordo (fondamentale, terza, quinta, 7a o estensione disponibile)." },
  { q: "Come si determina se una nota melodica è compatibile con un accordo di riarmonizzazione?", opts: ["La nota melodica deve essere nella scala di Do maggiore", "La nota melodica deve essere una fondamentale, terza, quinta, 7a o estensione disponibile dell'accordo — non una nota da evitare", "Tutte le note sono compatibili con tutti gli accordi", "La nota melodica deve essere più acuta del basso"], a: 1, fb: "Vincolo principale della riarmonizzazione: la melodia non deve sfregare contro l'accordo. Se la nota melodica è una 'nota da evitare' (es.: 11a naturale su IMaj7 — Fa su CMaj7 crea attrito di semitono con la terza Mi), l'accordo è scelto male. Preferire un accordo la cui nota melodica sia fondamentale, 3a, 5a, 7a o tensione disponibile." },
  { q: "Cos'è il 'back-cycling' nella riarmonizzazione jazz?", opts: ["Suonare la griglia al contrario", "Aggiungere accordi di dominante che precedono ogni accordo importante per moto di quinte — IIm→V prima di ogni accordo bersaglio", "Ripetere la griglia il doppio più lentamente", "Rimuovere accordi dalla griglia originale"], a: 1, fb: "Il back-cycling aggiunge dominanti secondarie prima di ogni accordo bersaglio. Se la griglia ha CMaj7, lo si precede con G7 (dominante di Do). Se ha Am7, lo si precede con E7 (dominante di La). Questa tecnica 'risale il ciclo delle quinte' e densifica il ritmo armonico — tipico del jazz bebop." },
  { q: "Cos'è la 'sostituzione diminuita' nel jazz?", opts: ["Sostituire un accordo con il suo diminuito parallelo", "Sostituire un accordo dominante 7b9 con l'accordo diminuito costruito sulla sua guide-tone — condividono 4 note comuni", "Suonare accordi diminuiti su tutti i tempi deboli", "Usare solo scale diminuite"], a: 1, fb: "G7b9 (Sol–Si–Re–Fa–Lab) condivide 4 note con B°7 (Si–Re–Fa–Lab). Questi due accordi sono armonicamente equivalenti — uno può sostituire l'altro. L'accordo diminuito può 'salire' la tonica di un semitono: B°7 = Bdim = D°7 = F°7 = Ab°7 (le 4 forme dello stesso accordo), tutti sostituibili a G7b9." },
  { q: "Qual è la progressione II–V–I in La♭ maggiore?", opts: ["Am7–D7–GMaj7", "Bbm7–Eb7–AbMaj7", "Gm7–C7–FMaj7", "Fm7–Bb7–EbMaj7"], a: 1, fb: "In Lab maggiore: IIm7 = Sib minore 7 (Bbm7), V7 = Mib7 (Eb7), IMaj7 = Lab maggiore 7 (AbMaj7). Il II–V–I in Lab maggiore è Bbm7–Eb7–AbMaj7. La fondamentale del II è un tono sopra I (Sib sopra Lab), la fondamentale del V è una quarta sopra I (Mib sopra Lab)." },
  { q: "Cos'è un 'passing chord' (accordo di passaggio) nella riarmonizzazione?", opts: ["Un accordo suonato molto piano", "Un accordo cromatico interstiziale inserito tra due accordi per creare un movimento di basso cromatico fluido", "Un accordo di transizione obbligatorio", "L'accordo di sottodominante in qualsiasi progressione"], a: 1, fb: "Un passing chord è un accordo aggiunto (spesso diminuito o dominante) tra due accordi della griglia per creare movimento cromatico di basso. CMaj7→Am7 può diventare CMaj7→Do#°7→Am7. Il basso fa Do–Do#–La; il passing chord crea una tensione cromatica che l'accordo successivo risolve." },
  { q: "Cos'è uno 'shell voicing' nel jazz?", opts: ["Un accordo suonato con il guscio di una sola mano", "Un accordo ridotto alle sue note essenziali: fondamentale + 3a + 7a (senza quinta) — lo scheletro dell'accordo", "Un accordo in posizione aperta", "Un accordo senza fondamentale"], a: 1, fb: "Lo shell voicing mantiene solo fondamentale, 3a e 7a — le guide-tones essenziali. La quinta è omessa perché non aggiunge colore. CMaj7 shell: Do–Mi–Si. G7 shell: Sol–Si–Fa. Questo voicing suona pulito e lascia spazio per la melodia e le estensioni. Ideale per accompagnare una voce." },
  { q: "Come si costruisce un 'drop 2 voicing' a partire da un accordo in posizione chiusa?", opts: ["Abbassare la fondamentale di un'ottava", "Prendere un accordo in posizione chiusa e abbassare la 2a voce dall'alto di un'ottava", "Suonare l'accordo due ottave più in basso", "Omettere la nota più acuta"], a: 1, fb: "Drop 2: CMaj7 in posizione chiusa (Do–Mi–Sol–Si, dal grave all'acuto). La 2a voce dall'alto è Sol. Abbassarla di un'ottava: Do–Sol(8vb)–Si–Mi. Risultato: Do–Sol–Si–Mi — voicing aperto e pianistico. Questa tecnica è fondamentale per i chitarristi e pianisti jazz — apre l'accordo su un registro più ampio." },
  { q: "Cos'è un 'rootless voicing' nel jazz?", opts: ["Un accordo suonato senza il musicista principale", "Un voicing che omette la fondamentale — la 3a, la 7a e le estensioni creano il colore senza l'ancoraggio tonale della fondamentale", "Un accordo suonato senza misura", "Un accordo suonato solo in ottave"], a: 1, fb: "Il rootless voicing elimina la fondamentale perché è suonata dal contrabbasso. Senza fondamentale, l'accordo suona più 'aperto', meno ancorato — ideale per le armonie fluttuanti del jazz modale. CMaj9 rootless: Mi–Sol–Si–Re (3a–5a–7a–9a). G13 rootless: Si–Re–Fa–Mi (3a–5a–7a–13a)." },
  { q: "Come si costruisce il 'So What voicing' su qualsiasi nota di basso?", opts: ["Nota + terza + terza + terza + quinta", "Nota + quarta + quarta + quarta + terza maggiore in cima (4 quarte sovrapposte + terza maggiore)", "Nota + quinta + terza + quinta", "Nota + seconda + terza + quarta"], a: 1, fb: "Il So What voicing segue sempre: Nota + quarta + quarta + quarta + terza maggiore. Su Re: Re–Sol–Do–Fa–La. Su Sol: Sol–Do–Fa–Sib–Re. Su Do: Do–Fa–Sib–Mib–Sol. Questa formula è universale — si trasporta esattamente su tutte le 12 note cromatiche. È il voicing caratteristico del jazz modale." },
  { q: "Perché i 'quartal voicings' sono particolarmente adatti al jazz modale?", opts: ["Perché sono più facili da suonare", "Perché la loro ambiguità modale (né maggiore né minore) si adatta perfettamente alle modalità aperte senza progressione funzionale forte — 'fluttuano' armonicamente", "Perché sono più gravi", "Perché non hanno la settima"], a: 1, fb: "Il jazz modale (Miles Davis, John Coltrane, McCoy Tyner) usa poche progressioni funzionali V→I — l'armonia rimane statica o cambia lentamente. I voicings di quarte sono perfetti per questo contesto perché l'assenza di una terza evita di definire un modo maggiore o minore preciso — l'accordo è ambiguo e 'fluttua' armonicamente." },
];

const questionsPt: Question[] = [
  { q: "O que é a 'substituição diatónica' na rearmonização?", opts: ["Substituir um acorde por um de outra tonalidade", "Substituir um acorde por outro com a mesma função harmónica na mesma tonalidade — ex. I ↔ III ↔ VI", "Substituir todos os acordes por acordes de dominante", "Mudar de tonalidade a cada acorde"], a: 1, fb: "A substituição diatónica explora acordes que partilham notas comuns na mesma tonalidade. I ↔ III ↔ VI funcionam porque partilham 2 de 3 notas. II ↔ IV são intercambiáveis porque partilham a mesma função de subdominante e 2 notas comuns. A melodia continua harmonizável com o substituto." },
  { q: "Qual é o princípio fundamental da substituição de trítono?", opts: ["Substituir a tónica pela dominante", "Substituir um acorde dominante V7 pelo acorde dominante situado um trítono abaixo — partilham as mesmas guide-tones (3.ª e 7.ª, trocadas)", "Substituir o IIm7 pelo IVmaj7", "Transpor toda a grelha um trítono acima"], a: 1, fb: "G7 (Sol–Si–Ré–Fá) e Db7 (Réb–Fá–Láb–Dó) partilham as mesmas guide-tones: Si (3.ª de G7) = Dó# (7.ª de Db7) e Fá (7.ª de G7) = Mib (3.ª de Db7). Estas duas notas trocam os seus papéis — por isso ambos os acordes têm o mesmo poder resolutivo para Dó. O baixo desce por semitom (Sol→Réb) em vez de uma quinta (Sol→Dó)." },
  { q: "O que é a 'troca modal avançada' para além do eólio e do mixolídio?", opts: ["Usar apenas os modos jónico e dórico", "Emprestar acordes de modos paralelos não diatónicos — incluindo o frígio (bII) e o lócrio (bII dim)", "Mudar de tonalidade para um único acorde", "Tocar em modo maior e menor simultaneamente"], a: 1, fb: "Para além dos empréstimos padrão (bVI do eólio, bVII do mixolídio), a troca modal avançada permite emprestar do modo frígio (bII Maior — o acorde napolitano) ou do lócrio (VIIdim). Em Dó maior: Réb Maior (frígio), Si dim (lócrio). Estes empréstimos mais raros criam cores muito características." },
  { q: "O que é a 'mediante cromática' na rearmonização?", opts: ["Substituir a tónica pela mediante da escala cromática", "Substituir o acorde de tónica por um acorde cuja fundamental está a uma terça (maior ou menor) — maior → menor ou vice-versa", "Usar exclusivamente acordes cromáticos alterados", "Tocar a melodia um semitom mais agudo"], a: 1, fb: "A mediante cromática substitui I por III, VI ou o seu equivalente modificado. Em Dó maior: I (Dó M) pode ser substituído por Mi M (terça maior, modo paralelo diferente) ou Láb M (terça maior descendente). Estas substituições criam uma cor 'mágica' e cinemática muito usada por John Williams e Hans Zimmer." },
  { q: "O que é um 'chord scale' (escala por acorde)?", opts: ["Uma escala construída sobre as notas do acorde", "A escala específica a tocar sobre cada acorde num contexto harmónico dado — cada acorde determina qual a escala ideal para a improvisação", "Um acorde construído sobre as notas da escala", "Uma escala cromática alterada"], a: 1, fb: "O chord scale associa a cada acorde a escala mais compatível. CMaj7 → lídio (para #11) ou jónico (para a cor clássica). Dm7 → dórico (para a 13.ª natural e a cor jazz). G7 → mixolídio (padrão) ou alterado (superlócrio, para tensão máxima). O chord scale determina quais as notas 'disponíveis' para a improvisação." },
  { q: "Sobre que escala improvisar em G7alt (dominante alterado)?", opts: ["Escala maior de Sol", "Escala mixolídia de Sol", "Escala alterada de Sol (superlócrio = 7.º modo do menor melódico)", "Escala pentatónica de Sol"], a: 2, fb: "G7alt usa a escala alterada de Sol (Sol–Láb–Sib–Si–Réb–Mib–Fá), também chamada superlócria porque é o 7.º modo da escala menor melódica de Láb. Contém todas as tensões alteradas: b9 (Láb), #9 (Lá# = Sib), #11 (Dó# = Réb), b13 (Mib). É a escala de tensão máxima sobre V7." },
  { q: "O que é um 'turnaround' no jazz?", opts: ["Um vai-e-vem entre tónica e dominante", "Uma curta progressão (frequentemente 2–4 acordes) no final de uma secção que regressa ao início — tipicamente I–VI–II–V ou III–VI–II–V", "Um solo instrumental", "Uma mudança de andamento"], a: 1, fb: "O turnaround é a progressão de fim de secção que relança a grelha para o seu início. Fórmula clássica: I–VI–II–V (CMaj–Am7–Dm7–G7). O VI é frequentemente substituído por um substituto (mediante cromática, substituto de trítono). Coltrane reinventou o turnaround com as suas substituições de terceiras maiores." },
  { q: "Em 'Autumn Leaves', qual é a progressão harmónica básica dos primeiros 8 compassos?", opts: ["I–IV–VII–III–VI–II–V–I (ciclo de quintas completo)", "Cm7–F7–BbMaj7–EbMaj7–Am7b5–D7–Gm (ciclo de quintas em Sol menor)", "Im–bVI–bIII–bVII–Im", "IIm7–V7–IMaj7 repetido 4 vezes"], a: 1, fb: "Autumn Leaves segue a progressão clássica: ciclo de quintas em Sol menor — Cm7–F7–BbMaj7–EbMaj7–Am7b5–D7–Gm. É o standard de jazz mais pedagógico porque contém tanto um II–V–I em Sib maior como um II–V–I em Sol menor, com pivô harmónico entre os dois." },
  { q: "O que é a 'rearmonização à Coltrane' aplicada a um standard?", opts: ["Substituir cada acorde pelo seu substituto de trítono", "Substituir um II–V–I por vários II–V–I sucessivos à distância de terça maior (ciclo das três tónicas)", "Tocar apenas acordes de sétima diminuta", "Remover todos os acordes menores"], a: 1, fb: "A rearmonização à Coltrane divide o ciclo tonal em terceiras maiores. Em vez de um único II–V–I (Dm7–G7–CMaj), percorrem-se três II–V–I à distância de terça: Dm7–G7–CMaj → Hm7–E7–AMaj → Abm7–Db7–GbMaj → regresso. O triângulo Si–Sol–Mib–Si cobre as 12 tonalidades em 3 saltos de terça." },
  { q: "Qual é a diferença entre 'rearmonização' e 'harmonização'?", opts: ["São sinónimos", "A harmonização adiciona acordes sob uma melodia sem acompanhamento; a rearmonização substitui acordes existentes por outros sob a mesma melodia", "A rearmonização diz respeito apenas ao jazz, a harmonização à música clássica", "A rearmonização é mais simples"], a: 1, fb: "Harmonizar = criar uma primeira harmonização para uma melodia nua. Rearmonizar = substituir os acordes de uma harmonização existente por outros, mantendo a melodia. Condição principal: a nota melódica deve ser compatível com o novo acorde (fundamental, terça, quinta, 7.ª ou extensão disponível)." },
  { q: "Como se determina se uma nota melódica é compatível com um acorde de rearmonização?", opts: ["A nota melódica deve estar na escala de Dó maior", "A nota melódica deve ser fundamental, terça, quinta, 7.ª ou extensão disponível do acorde — não uma nota a evitar", "Todas as notas são compatíveis com todos os acordes", "A nota melódica deve ser mais aguda que o baixo"], a: 1, fb: "Condição principal da rearmonização: a melodia não deve friccionar contra o acorde. Se a nota melódica for uma 'nota a evitar' (ex.: 11.ª natural sobre IMaj7 — Fá sobre CMaj7 cria atrito de semitom com a terça Mi), o acorde está mal escolhido. Preferir um acorde cuja nota melódica seja fundamental, 3.ª, 5.ª, 7.ª ou tensão disponível." },
  { q: "O que é o 'back-cycling' na rearmonização jazz?", opts: ["Tocar a grelha ao contrário", "Adicionar acordes de dominante que precedem cada acorde importante por movimento de quintas — IIm→V antes de cada acorde alvo", "Repetir a grelha duas vezes mais devagar", "Retirar acordes da grelha original"], a: 1, fb: "O back-cycling adiciona dominantes secundárias antes de cada acorde alvo. Se a grelha tem CMaj7, precede-se com G7 (dominante de Dó). Se tem Am7, precede-se com E7 (dominante de Lá). Esta técnica 'sobe o ciclo das quintas' e densifica o ritmo harmónico — típico do jazz bebop." },
  { q: "O que é a 'substituição diminuta' no jazz?", opts: ["Substituir um acorde pelo seu diminuto paralelo", "Substituir um acorde dominante 7b9 pelo acorde diminuto construído sobre a sua guide-tone — partilham 4 notas comuns", "Tocar acordes diminutos em todos os tempos fracos", "Usar apenas escalas diminutas"], a: 1, fb: "G7b9 (Sol–Si–Ré–Fá–Láb) partilha 4 notas com B°7 (Si–Ré–Fá–Láb). Estes dois acordes são harmonicamente equivalentes — um pode substituir o outro. O acorde diminuto pode 'subir' a tónica por semitom: B°7 = Bdim = D°7 = F°7 = Ab°7 (as 4 formas do mesmo acorde), todas substituíveis por G7b9." },
  { q: "Qual é a progressão II–V–I em Láb maior?", opts: ["Am7–D7–GMaj7", "Bbm7–Eb7–AbMaj7", "Gm7–C7–FMaj7", "Fm7–Bb7–EbMaj7"], a: 1, fb: "Em Láb maior: IIm7 = Sib menor 7 (Bbm7), V7 = Mib7 (Eb7), IMaj7 = Láb maior 7 (AbMaj7). O II–V–I em Láb maior é Bbm7–Eb7–AbMaj7. A fundamental do II está um tom acima de I (Sib acima de Láb), a fundamental do V está uma quarta acima de I (Mib acima de Láb)." },
  { q: "O que é um 'passing chord' (acorde de passagem) na rearmonização?", opts: ["Um acorde tocado muito suavemente", "Um acorde cromático intersticial inserido entre dois acordes para criar um movimento de baixo cromático fluido", "Um acorde de transição obrigatório", "O acorde de subdominante em qualquer progressão"], a: 1, fb: "Um passing chord é um acorde adicionado (frequentemente diminuto ou dominante) entre dois acordes da grelha para criar movimento cromático de baixo. CMaj7→Am7 pode tornar-se CMaj7→Dó#°7→Am7. O baixo faz Dó–Dó#–Lá; o passing chord cria uma tensão cromática que o acorde seguinte resolve." },
  { q: "O que é um 'shell voicing' no jazz?", opts: ["Um acorde tocado com a casca de uma mão apenas", "Um acorde reduzido às suas notas essenciais: fundamental + 3.ª + 7.ª (sem quinta) — o esqueleto do acorde", "Um acorde em posição aberta", "Um acorde sem fundamental"], a: 1, fb: "O shell voicing mantém apenas fundamental, 3.ª e 7.ª — as guide-tones essenciais. A quinta é omitida porque não adiciona cor. CMaj7 shell: Dó–Mi–Si. G7 shell: Sol–Si–Fá. Este voicing soa limpo e deixa espaço para a melodia e as extensões. Ideal para acompanhar uma voz." },
  { q: "Como se constrói um 'drop 2 voicing' a partir de um acorde em posição fechada?", opts: ["Baixar a fundamental uma oitava", "Pegar num acorde em posição fechada e baixar a 2.ª voz a partir de cima uma oitava", "Tocar o acorde duas oitavas mais grave", "Omitir a nota mais aguda"], a: 1, fb: "Drop 2: CMaj7 em posição fechada (Dó–Mi–Sol–Si, do grave ao agudo). A 2.ª voz a partir de cima é Sol. Baixá-la uma oitava: Dó–Sol(8vb)–Si–Mi. Resultado: Dó–Sol–Si–Mi — voicing aberto e pianístico. Esta técnica é fundamental para guitarristas e pianistas de jazz — abre o acorde para um registo mais amplo." },
  { q: "O que é um 'rootless voicing' no jazz?", opts: ["Um acorde tocado sem o músico principal", "Um voicing que omite a fundamental — a 3.ª, a 7.ª e as extensões criam a cor sem a âncora tonal da fundamental", "Um acorde tocado sem compasso", "Um acorde tocado apenas em oitavas"], a: 1, fb: "O rootless voicing elimina a fundamental porque ela é tocada pelo contrabaixo. Sem fundamental, o acorde soa mais 'aberto', menos ancorado — ideal para as harmonias flutuantes do jazz modal. CMaj9 rootless: Mi–Sol–Si–Ré (3.ª–5.ª–7.ª–9.ª). G13 rootless: Si–Ré–Fá–Mi (3.ª–5.ª–7.ª–13.ª)." },
  { q: "Como se constrói o 'So What voicing' sobre qualquer nota de baixo?", opts: ["Nota + terça + terça + terça + quinta", "Nota + quarta + quarta + quarta + terça maior no topo (4 quartas empilhadas + terça maior)", "Nota + quinta + terça + quinta", "Nota + segunda + terça + quarta"], a: 1, fb: "O So What voicing segue sempre: Nota + quarta + quarta + quarta + terça maior. Sobre Ré: Ré–Sol–Dó–Fá–Lá. Sobre Sol: Sol–Dó–Fá–Sib–Ré. Sobre Dó: Dó–Fá–Sib–Mib–Sol. Esta fórmula é universal — transpõe-se exactamente para as 12 notas cromáticas. É o voicing característico do jazz modal." },
  { q: "Por que razão os 'quartal voicings' são particularmente adequados para o jazz modal?", opts: ["Porque são mais fáceis de tocar", "Porque a sua ambiguidade modal (nem maior nem menor) se adapta perfeitamente às modalidades abertas sem progressão funcional forte — 'flutuam' harmonicamente", "Porque são mais graves", "Porque não têm sétima"], a: 1, fb: "O jazz modal (Miles Davis, John Coltrane, McCoy Tyner) usa poucas progressões funcionais V→I — a harmonia permanece estática ou muda lentamente. Os voicings de quartas são perfeitos para este contexto porque a ausência de terça evita definir um modo maior ou menor preciso — o acorde é ambíguo e 'flutua' harmonicamente." },
];

